import { describe, it, expect } from 'vitest';
import { designPrimers } from '../src/lib/bio/primer-design';

describe('designPrimers', () => {
  it('returns primer pairs for valid sequence', () => {
    const seq = '';
    const result = designPrimers(seq);
    expect(result.forward.length).toBeGreaterThan(0);
    expect(result.reverse.length).toBeGreaterThan(0);
  });

  it('all primer TMs are within 50-65°C', () => {
    const seq = '';
    const result = designPrimers(seq);
    for (const p of result.forward) {
      expect(p.tm).toBeGreaterThanOrEqual(50);
      expect(p.tm).toBeLessThanOrEqual(65);
    }
  });

  it('product size is within valid range', () => {
    const seq = '';
    const result = designPrimers(seq);
    for (const p of result.pairs) {
      expect(p.productSize).toBeGreaterThanOrEqual(100);
      expect(p.productSize).toBeLessThanOrEqual(2000);
    }
  });
});
